mapper.update:
UPDATE "file_processing_task"
SET "status" = 'COMPLETED', "lease_token" = NULL, "lease_until" = NULL, "last_error" = ''
WHERE "id" = #{id} AND "status" = 'RUNNING' AND "lease_token" = #{leaseToken}

UPDATE "file_processing_task"
SET "status" = 'FAILED', "lease_token" = NULL, "lease_until" = NULL, "last_error" = #{lastError}
WHERE "id" = #{id} AND "status" = 'RUNNING' AND "lease_token" = #{leaseToken}

UPDATE "file_processing_task"
SET "lease_until" = NOW() + (#{leaseSeconds} * INTERVAL '1 second')
WHERE "id" = #{id} AND "status" = 'RUNNING' AND "lease_token" = #{leaseToken}
